import React from "react";
import { Link } from "react-router-dom";
import "./Artists.css";

function Artists() {
  const artists = [
    { id: "alice", name: "Alice", bio: "Peintre grenobloise passionnée de couleurs.", img: "/img/artist-alice.jpg" },
    { id: "bob", name: "Bob", bio: "Sculpteur inspiré par la nature.", img: "/img/artist-bob.jpg" },
    { id: "claire", name: "Claire", bio: "Dessins et encres poétiques.", img: "/img/artist-claire.jpg" },
  ];

  return (
    <div className="artists-container">
      <h2>Nos Artistes</h2>
      <div className="artists-grid">
        {artists.map((artist) => (
          <div key={artist.id} className="artist-card">
            <img src={artist.img} alt={artist.name} />
            <h3>{artist.name}</h3>
            <p>{artist.bio}</p>
            <Link to={`/artist/${artist.id}`} className="artist-link">
              Voir la galerie
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Artists;
